// // This comment suggests that the circuit will output LOW when any non-zero value is detected, which is the opposite of the actual behavior.
module top_module(
    input clk,
    input [3:0] stock,
    output reg hay          
    );always @(posedge clk) begin       
            case(stock)
                4'b0000: hay = 0;   
                default: hay = 1;   
            endcase
    end
endmodule
